import React from 'react';
import PageLogo from '../Logo/GnuLinuxLogo.svg';
import HeaderInfoBackgroundImage from '../Background/HeaderInfoBackgroundImage.jpg';
import HeaderInfoGitHubLogo from '../Logo/GitHubLogo.svg';

import '../HeaderInfo.css';

class HeaderInfo extends React.Component {
  constructor(props) {
    super(props);
    this.state = {
      domainLogo: props.domainLogo || PageLogo,
      currentPageName: props.currentPageName || '',
      backgroundImage: props.backgroundImage || HeaderInfoBackgroundImage,
      githubLogo: props.githubLogo || HeaderInfoGitHubLogo,
      githubURL: props.githubURL || "www.github.com",
      githubPagesURL: props.githubPagesURL || "www.github.com",
      domainName: props.domainName || "www.unix69.githubio.com",
      pageName: props.pageName || "Unix69",
      headerInfoClass: props.headerInfoClass || "header-info",
      headerInfoBackgroundImageClass: props.headerInfoBackgroundImageClass || "header-info-background-image",
      headerInfoDomainInfoClass: props.headerInfoClass || "header-info-domain-info",
      headerInfoDomainUrlClass: props.headerInfoDomainUrlClass || "header-info-domain-url",
      headerInfoDomainLogoClass: props.headerInfoDomainLogoClass || "header-info-domain-logo",
      headerInfoDomainPageClass: props.headerInfoDomainPageClass ||  "header-info-domain-page",
      headerInfoGitHubInfoClass: props.headerInfoGitHubInfoClass || "header-info-github-info",
      headerInfoGitHubUrlClass: props.headerInfoGitHubUrlClass || "header-info-github-url",
      headerInfoGitHubPagesUrlClass: props.headerInfoGitHubPagesUrlClass || "header-info-github-pages-url",
      headerInfoGitHubLogoClass: props.headerInfoGitHubLogoClass || "header-info-github-logo",
      headerInfoGitHubPagesLogoClass: props.headerInfoGitHubPagesLogoClass || "header-info-github-pages-logo"
    };
  }

  render() {
    return (<div class={this.state.headerInfoClass}>
            <section class={this.state.headerInfoClass}>
              <div class={this.state.headerInfoDomainInfoClass}>
                  <img src={this.state.domainLogo} alt="Domain Logo" className={this.state.headerInfoDomainLogoClass}/>
                  <a href={this.state.domainName} class={this.state.headerInfoDomainUrlClass}>{this.state.pageName}</a>
                  <div class={this.state.headerInfoDomainPageClass}>{this.state.currentPageName}</div>
              </div>
              <div class={this.state.headerInfoGitHubInfoClass}>                 
                  <a href={this.state.githubURL} class={this.state.headerInfoGitHubUrlClass}/>
                  <img src={this.state.githubLogo} alt="GitHub Logo" class={this.state.headerInfoGitHubLogoClass}/>
                  <a href={this.state.githubPagesURL} class={this.state.headerInfoGitHubPagesUrlClass}>{this.state.githubPagesURL}</a>
              </div>
            </section>
            </div>
    );
  }
}

export default HeaderInfo;
